import React, { useContext, useRef, useState } from 'react';
import ReactDOM from 'react-dom';
import { SettingsContext, DEFAULT_SETTINGS } from '../contexts/SettingsContext';
import { currencies } from '../utils/currency';
import ModalHeader from './ModalHeader';
import CustomSelect from './CustomSelect';
import { AppState, Theme, TrustBinDeletionPeriodUnit } from '../types';
import { createBackup, restoreBackup } from '../utils/backup';
import ConfirmationDialog from './ConfirmationDialog';

const modalRoot = document.getElementById('modal-root')!;

interface AppSettingsModalProps {
  onClose: () => void;
  appState: AppState;
  onRestore: (state: AppState) => void;
}

export const AppSettingsModal: React.FC<AppSettingsModalProps> = ({ onClose, appState, onRestore }) => {
  const settingsContext = useContext(SettingsContext);
  if (!settingsContext) throw new Error("SettingsContext not found");
  const { settings, setSettings } = settingsContext;
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isResetDialogOpen, setIsResetDialogOpen] = useState(false);

  const handleCurrencyChange = (currencyCode: string) => {
    setSettings(prev => ({ ...prev, currency: currencyCode }));
  };

  const handleThemeChange = (theme: Theme) => {
    setSettings(prev => ({ ...prev, theme: theme }));
  }

  const handleLanguageChange = (languageCode: string) => {
    setSettings(prev => ({ ...prev, language: languageCode }));
  };

  const handleTrustBinPeriodChange = (field: 'value' | 'unit', value: string | number) => {
      setSettings(prev => ({
          ...prev,
          trustBinDeletionPeriod: {
              ...prev.trustBinDeletionPeriod,
              [field]: field === 'value' ? parseInt(value as string, 10) : value
          }
      }))
  }

  const handleCreateBackup = async () => {
      const password = prompt("Please enter a password to encrypt your backup. This password will be required to restore your data.");
      if(password) {
          try {
            await createBackup(appState, password);
            alert("Backup created successfully!");
          } catch(err) {
              console.error("Backup failed", err);
              alert("Backup failed. See console for details.");
          }
      }
  };

  const handleRestoreClick = () => {
      fileInputRef.current?.click();
  }

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
      const file = event.target.files?.[0];
      if (file) {
          const password = prompt("Please enter the password for this backup file.");
          if(password){
              try {
                  const restoredState = await restoreBackup(file, password);
                  if (window.confirm("Restore successful. This will overwrite all current data. Are you sure you want to continue?")) {
                      onRestore(restoredState);
                  }
              } catch(err) {
                  console.error("Restore failed", err);
                  alert(`Restore failed: ${err instanceof Error ? err.message : "Unknown error"}`);
              }
          }
      }
      if(fileInputRef.current) fileInputRef.current.value = "";
  };

  const handleConfirmReset = () => {
    setSettings(DEFAULT_SETTINGS);
    setIsResetDialogOpen(false);
    alert("Settings have been reset to default values.");
  };

  const currencyOptions = currencies.map(c => ({
    value: c.code,
    label: `${c.name} (${c.symbol})`
  }));

  const languageOptions = [
    { value: 'en', label: 'English' },
    { value: 'hi', label: 'हिन्दी (Hindi)' },
    { value: 'ta', label: 'தமிழ் (Tamil)' },
    { value: 'ml', label: 'മലയാളം (Malayalam)' },
  ];

  const trustBinUnitOptions: {value: TrustBinDeletionPeriodUnit, label: string}[] = [
      {value: 'minutes', label: 'Minutes'},
      {value: 'hours', label: 'Hours'},
      {value: 'days', label: 'Days'},
      {value: 'weeks', label: 'Weeks'},
      {value: 'months', label: 'Months'},
      {value: 'years', label: 'Years'},
  ];

  const TabButton: React.FC<{ active: boolean, children: React.ReactNode, onClick: () => void}> = ({ active, children, onClick }) => (
    <button type="button" onClick={onClick} className={`px-4 py-2 text-sm font-semibold rounded-full transition-colors w-full ${active ? 'bg-emerald-500 text-white' : 'bg-subtle text-primary hover-bg-stronger'}`}>
      {children}
    </button>
  );

  const modalContent = (
    <>
      <ConfirmationDialog
        isOpen={isResetDialogOpen}
        title="Confirm Reset Settings"
        message="Are you sure you want to reset all app settings to their default values? This will not affect your financial data like transactions or accounts."
        onConfirm={handleConfirmReset}
        onCancel={() => setIsResetDialogOpen(false)}
        confirmLabel="Reset"
      />
      <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-md flex items-center justify-center z-50 p-4" onClick={onClose}>
        <div className="glass-card rounded-xl shadow-2xl w-full max-w-md p-0 max-h-[90vh] flex flex-col border border-divider animate-scaleIn" onClick={e => e.stopPropagation()}>
          <ModalHeader title="App Settings" onClose={onClose} icon="⚙️" />
          <div className="p-6 space-y-6 overflow-y-auto flex-grow">
            <div className="p-4 bg-subtle rounded-lg">
                <h4 className="font-semibold text-primary mb-3">Appearance</h4>
                <div className="flex items-center justify-between">
                    <span className="text-sm font-medium text-secondary">Theme</span>
                    <div className="flex items-center gap-2 bg-subtle p-1 rounded-full border border-divider">
                        <TabButton active={settings.theme === 'dark'} onClick={() => handleThemeChange('dark')}>Dark</TabButton>
                        <TabButton active={settings.theme === 'light'} onClick={() => handleThemeChange('light')}>Light</TabButton>
                    </div>
                </div>
            </div>

             <div className="p-4 bg-subtle rounded-lg space-y-3">
                <h4 className="font-semibold text-primary mb-3">Regional</h4>
                <div><label className="text-sm font-medium text-secondary mb-1">Default Currency</label><CustomSelect options={currencyOptions} value={settings.currency} onChange={handleCurrencyChange} /></div>
                <div>
                  <label className="text-sm font-medium text-secondary mb-1">Language</label>
                  <CustomSelect options={languageOptions} value={settings.language || 'en'} onChange={handleLanguageChange} />
                </div>
            </div>

            <div className="p-4 bg-subtle rounded-lg space-y-3">
                <h4 className="font-semibold text-primary mb-3">Data Management</h4>
                <div className="grid grid-cols-2 gap-3">
                    <button onClick={handleCreateBackup} className="button-secondary w-full py-2">Create Backup</button>
                    <button onClick={handleRestoreClick} className="button-secondary w-full py-2">Restore Backup</button>
                    <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".pfh" className="hidden" />
                </div>
                <div>
                    <label className="text-sm font-medium text-secondary mb-1">Trust Bin Period</label>
                    <div className="grid grid-cols-2 gap-2">
                        <input type="number" onWheel={e => e.currentTarget.blur()} value={settings.trustBinDeletionPeriod.value} onChange={e => handleTrustBinPeriodChange('value', e.target.value)} className="input-base w-full p-2 rounded-lg" />
                        <CustomSelect options={trustBinUnitOptions} value={settings.trustBinDeletionPeriod.unit} onChange={v => handleTrustBinPeriodChange('unit', v)} />
                    </div>
                </div>
            </div>

            <div className="p-4 rounded-lg bg-rose-900/20 border border-rose-500/30 space-y-2">
                <h4 className="font-semibold text-rose-300">Reset to Default</h4>
                <div className="text-right">
                    <button type="button" onClick={() => setIsResetDialogOpen(true)} className="text-xs font-bold text-rose-400 hover:underline">
                        Reset All Settings
                    </button>
                </div>
            </div>

            <div className="text-center pt-8 pb-4">
                <p className="text-xs font-bold uppercase tracking-widest text-blue-500">Created by Kadhiravan</p>
                <p className="text-[10px] text-tertiary mt-1">Finance Hub v2.1.0</p>
            </div>
          </div>
        </div>
      </div>
    </>
  );

  return ReactDOM.createPortal(modalContent, modalRoot);
};

import React, { useMemo } from 'react';
import { Transaction, RecurringTransaction, Account, AccountType } from '../types';
import { useCurrencyFormatter } from '../hooks/useCurrencyFormatter';

interface BalanceForecastProps {
  transactions: Transaction[];
  accounts: Account[];
  recurring: RecurringTransaction[];
  isVisible: boolean;
}

const BalanceForecast: React.FC<BalanceForecastProps> = ({ transactions, accounts, recurring, isVisible }) => {
  const formatCurrency = useCurrencyFormatter();

  const forecast = useMemo(() => {
    // 1. Calculate Current Balances for Depository Accounts
    const balances = transactions.reduce((acc, t) => {
        acc[t.accountId] = (acc[t.accountId] || 0) + (t.type === 'income' ? t.amount : -t.amount);
        return acc;
    }, {} as Record<string, number>);

    const currentTotal = accounts
        .filter(a => a.accountType === AccountType.DEPOSITORY)
        .reduce((sum, a) => sum + (balances[a.id] || 0), 0);

    // 2. Identify Pending Bills for this Month
    const now = new Date();
    const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);
    endOfMonth.setHours(23, 59, 59, 999);

    const pendingBills = recurring.filter(r => {
        const dueDate = new Date(r.nextDueDate);
        return dueDate >= now && dueDate <= endOfMonth;
    });

    const pendingTotal = pendingBills.reduce((sum, r) => {
        return sum + (r.type === 'expense' ? r.amount : -r.amount);
    }, 0);

    const projectedBalance = currentTotal - pendingTotal;
    const safetyMargin = projectedBalance > 0 ? (projectedBalance / currentTotal) * 100 : 0;

    return { projectedBalance, pendingTotal, currentTotal, safetyMargin, billCount: pendingBills.length };
  }, [transactions, accounts, recurring]);

  if (forecast.currentTotal === 0 && forecast.billCount === 0) return null;

  return (
    <div className="mb-6 p-4 rounded-xl glass-card animate-fadeInUp border-l-4 border-sky-500">
      <div className="flex justify-between items-start mb-2">
          <div>
            <h3 className="font-bold text-primary">Monthly Forecast</h3>
            <p className="text-xs text-secondary">Based on {forecast.billCount} upcoming bills</p>
          </div>
          <span className="text-xl">🔮</span>
      </div>

      <div className="flex items-center justify-between mt-4">
          <div>
              <p className="text-xs text-secondary uppercase font-bold tracking-tighter">Est. Month-End Balance</p>
              <p className={`text-2xl font-bold ${forecast.projectedBalance < 0 ? 'text-rose-400' : 'text-emerald-400'}`}>
                {isVisible ? formatCurrency(forecast.projectedBalance) : '••••'}
              </p>
          </div>
          <div className="text-right">
              <p className="text-xs text-secondary uppercase font-bold tracking-tighter">Bills Remaining</p>
              <p className="text-lg font-bold text-rose-400">
                {isVisible ? formatCurrency(forecast.pendingTotal) : '••••'}
              </p>
          </div>
      </div>

      <div className="mt-4">
          <div className="flex justify-between text-[10px] text-tertiary mb-1 font-bold uppercase">
              <span>Safety Margin</span>
              <span>{isVisible ? `${Math.round(forecast.safetyMargin)}%` : '••%'}</span>
          </div>
          <div className="w-full bg-subtle rounded-full h-1.5 overflow-hidden">
              <div 
                className={`h-full transition-all duration-1000 ${forecast.safetyMargin > 30 ? 'bg-emerald-500' : forecast.safetyMargin > 10 ? 'bg-yellow-500' : 'bg-rose-500'}`}
                style={{ width: `${Math.min(forecast.safetyMargin, 100)}%` }}
              />
          </div>
      </div>
    </div>
  );
};

export default BalanceForecast;

import React, { useMemo, useState, useContext } from 'react';
import { Transaction, TransactionType, DateRange, CustomDateRange, DashboardWidget, AppState, ActiveModal, Category, Account } from '../types';
import TransactionFilters from './TransactionFilters';
import BudgetsSummary from './BudgetsSummary';
import UpcomingBills from './UpcomingBills';
import { useCurrencyFormatter } from '../hooks/useCurrencyFormatter';
import GoalsSummary from './GoalsSummary';
import DebtsSummary from './DebtsSummary';
import NetWorthSummary from './NetWorthSummary';
import PortfolioSummary from './PortfolioSummary';
import FinancialHealthScore from './FinancialHealthScore';
import DynamicAIInsights from './DynamicAIInsights';
import EmptyState from './EmptyState';
import { AppDataContext } from '../contexts/SettingsContext';
import { getCategoryPath } from '../utils/categories';
import { parseNaturalLanguageQuery } from '../services/geminiService';
import NetWorthTrendChart from './NetWorthTrendChart';
import CategoryPieChart from './CategoryPieChart';
import BalanceForecast from './BalanceForecast';

interface FinanceDisplayProps {
  transactions: Transaction[];
  allTransactions: AppState['transactions'];
  accounts: AppState['accounts'];
  categories: AppState['categories'];
  budgets: AppState['budgets'];
  recurringTransactions: AppState['recurringTransactions'];
  goals: AppState['goals'];
  investmentHoldings: AppState['investmentHoldings'];
  onPayRecurring: (item: AppState['recurringTransactions'][0]) => void;
  onEdit: (transaction: Transaction) => void;
  onDelete: (id: string) => void;
  onSettleDebt: (transactionId: string, splitDetailId: string, settlementAccountId: string, amount: number) => void;
  dashboardWidgets: DashboardWidget[];
  financialProfile: AppState['financialProfile'];
  onOpenFinancialHealth: () => void;
  onAddTransaction: () => void;
  openModal: (name: ActiveModal, props?: Record<string, any>) => void;
  onUpdateTransaction: (transaction: Transaction) => void;
  baseCurrency: string;
}

const FinanceDisplay: React.FC<FinanceDisplayProps> = (props) => {
  const { transactions, allTransactions, accounts, categories, dashboardWidgets, onEdit } = props;
  const [searchQuery, setSearchQuery] = useState('');
  const [dateFilter, setDateFilter] = useState<DateRange>('month');
  const [customDateRange, setCustomDateRange] = useState<CustomDateRange>({ start: null, end: null });

  const onNaturalLanguageSearch = async () => {
      try {
        const result = await parseNaturalLanguageQuery(searchQuery);
        if (result.dateFilter) setDateFilter(result.dateFilter);
        setSearchQuery(result.searchQuery);
      } catch (error) {
          console.error("NLP search failed:", error);
      }
  };

  const filteredTransactions = useMemo(() => {
    let filtered = transactions;
    if (searchQuery) {
      filtered = filtered.filter(t => t.description.toLowerCase().includes(searchQuery.toLowerCase()));
    }
    return filtered;
  }, [transactions, searchQuery]);

  const { totalIncome, totalExpenses, netChange } = useMemo(() => {
    return filteredTransactions.reduce((acc, t) => {
      if (t.type === TransactionType.INCOME) acc.totalIncome += t.amount;
      else acc.totalExpenses += t.amount;
      acc.netChange = acc.totalIncome - acc.totalExpenses;
      return acc;
    }, { totalIncome: 0, totalExpenses: 0, netChange: 0 });
  }, [filteredTransactions]);

  const renderWidget = (widget: DashboardWidget) => {
    switch (widget.id) {
      case 'summary': return <PeriodSummary key={widget.id} income={totalIncome} expense={totalExpenses} net={netChange} />;
      case 'netWorth': return <NetWorthSummary key={widget.id} accounts={accounts} allTransactions={allTransactions} holdings={props.investmentHoldings} isVisible={true} />;
      case 'financialHealth': return <FinancialHealthScore key={widget.id} scoreData={props as unknown as AppState} onClick={props.onOpenFinancialHealth} />;
      case 'aiCoach': return <DynamicAIInsights key={widget.id} appState={props as unknown as AppState} dateFilter={dateFilter} />;
      case 'portfolio': return <PortfolioSummary key={widget.id} holdings={props.investmentHoldings} isVisible={true} />;
      case 'goals': return <GoalsSummary key={widget.id} goals={props.goals} isVisible={true} />;
      case 'budgets': return <BudgetsSummary key={widget.id} budgets={props.budgets} transactions={allTransactions} categories={categories} isVisible={true} />;
      case 'upcoming': return (
        <React.Fragment key={widget.id}>
            <BalanceForecast transactions={allTransactions} accounts={accounts} recurring={props.recurringTransactions} isVisible={true} />
            <UpcomingBills recurringTransactions={props.recurringTransactions} onPay={props.onPayRecurring} categories={categories} />
        </React.Fragment>
      );
      case 'debts': return <DebtsSummary key={widget.id} transactions={allTransactions} accounts={accounts} onSettle={props.onSettleDebt} isVisible={true} />;
      case 'netWorthTrend': return <NetWorthTrendChart key={widget.id} transactions={allTransactions} accounts={accounts} currency={props.baseCurrency} />;
      case 'charts': return <CategoryPieChart key={widget.id} title="Expense Breakdown" transactions={filteredTransactions} categories={categories} type={TransactionType.EXPENSE} isVisible={true} />;
      default: return null;
    }
  };

  return (
    <div className="dashboard-grid-container p-4 gap-4">
      <div className="dashboard-widgets-column pb-4 pr-1">
        {dashboardWidgets.filter(w => w.visible).map(renderWidget)}
      </div>
      <div className="transactions-column">
        <div className="flex-shrink-0">
          <TransactionFilters
            searchQuery={searchQuery}
            setSearchQuery={setSearchQuery}
            onNaturalLanguageSearch={onNaturalLanguageSearch}
            dateFilter={dateFilter}
            setDateFilter={setDateFilter}
            customDateRange={customDateRange}
            setCustomDateRange={setCustomDateRange}
          />
        </div>
        <div className="flex-grow overflow-y-auto mt-4 pr-1">
          {filteredTransactions.length === 0 ? (
            <EmptyState
              icon="🤷"
              title="No Transactions Found"
              message="No transactions match your current filters. Try a different date range or add a new transaction!"
              actionText="Add Transaction"
              onAction={props.onAddTransaction}
            />
          ) : (
            <div className="space-y-2">
              {filteredTransactions.map((t, index) => (
                <TransactionItem key={t.id} transaction={t} onEdit={onEdit} categories={categories} accounts={accounts} style={{'--stagger-index': index} as React.CSSProperties} />
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};


const PeriodSummary: React.FC<{income: number, expense: number, net: number}> = ({income, expense, net}) => {
    const formatCurrency = useCurrencyFormatter();
    return (
        <div className="mb-6 p-4 rounded-xl glass-card animate-fadeInUp">
            <div className="grid grid-cols-3 gap-4 text-center">
                <div><p className="text-sm text-secondary">Income</p><p className="font-bold text-lg text-emerald-400">{formatCurrency(income)}</p></div>
                <div><p className="text-sm text-secondary">Expenses</p><p className="font-bold text-lg text-rose-400">{formatCurrency(expense)}</p></div>
                <div><p className="font-bold text-lg text-primary">{formatCurrency(net)}</p></div>
            </div>
        </div>
    );
};

const TransactionItem: React.FC<{transaction: Transaction, onEdit: (t: Transaction) => void, categories: Category[], accounts: Account[], style: React.CSSProperties}> = ({transaction: t, onEdit, categories, accounts, style}) => {
    const account = accounts.find(a => a.id === t.accountId);
    const formatCurrency = useCurrencyFormatter(undefined, account?.currency);
    const category = categories.find(c => c.id === t.categoryId);
    return (
        <button onClick={() => onEdit(t)} style={style} className="w-full text-left p-3 glass-card rounded-lg stagger-delay flex justify-between items-center transition-all hover:translate-x-1 active:scale-[0.99]">
            <div className="flex items-center gap-3">
                <span className="text-xl flex-shrink-0">{category?.icon || '📁'}</span>
                <div>
                    <p className="font-semibold text-primary">{t.description}</p>
                    <p className="text-xs text-secondary">{getCategoryPath(t.categoryId, categories)}</p>
                </div>
            </div>
            <span className={`font-semibold ${t.type === 'income' ? 'text-emerald-400' : 'text-rose-400'}`}>{formatCurrency(t.amount)}</span>
        </button>
    );
};

export default FinanceDisplay;

import React, { useState, useContext, useMemo, useRef, useEffect } from 'react';
import { ActiveScreen, AppState, ModalState, ActiveModal, Transaction, RecurringTransaction, Account, AccountType, Goal, Budget, Trip, ShopSale, ShopProduct, TransactionType, Debt, Note, ItemizedDetail, TripExpense, DateRange, CustomDateRange, USER_SELF_ID, Category, Contact, ContactGroup, Shop, ShopEmployee, ShopShift, Refund, GlossaryEntry, CalendarEvent, FinancialProfile } from '../types';
import FinanceDisplay from './FinanceDisplay';
import { ReportsScreen } from './ReportsScreen';
import BudgetsScreen from './BudgetsScreen';
import GoalsScreen from './goalsScreen';
import InvestmentsScreen from './InvestmentsScreen';
import ScheduledPaymentsScreen from './ScheduledPaymentsScreen';
import MoreScreen from './More';
