interface MainContentProps {
  activeScreen: ActiveScreen;
  setActiveScreen: (screen: ActiveScreen) => void;
  modalStack: ModalState[];
  setModalStack: React.Dispatch<React.SetStateAction<ModalState[]>>;
  isOnline: boolean;
  mainContentRef: React.RefObject<HTMLElement>;
  onNavigate: (screen: ActiveScreen, modal?: ActiveModal, props?: Record<string, any>) => void;
  isLoading: boolean;
  initialText: string | null;
  onSharedTextConsumed: () => void;
  onGoalComplete: () => void;
  appState: AppState;
  tripDetailsId: string | null;
  noteId: string | null;
  openModal: (name: ActiveModal, props?: Record<string, any>) => void;
  onSaveProfile: (profile: FinancialProfile) => void;
}

const MainContent: React.FC<MainContentProps> = (props) => {
  const { activeScreen, appState, isLoading, onNavigate, setActiveScreen, onGoalComplete, tripDetailsId, noteId, openModal, onSaveProfile } = props;

  const dataContext = useContext(AppDataContext);

  if (!dataContext) {
    return null;
  }

  const { 
    selectedAccountIds, 
    setSelectedAccountIds, 
    deleteItem, 
    onAddAccount, 
    onDeleteAccount,
    setRecurringTransactions,
    setGoals,
    setTrips,
    setShops,
    setShopProducts,
    setShopSales,
    setShopEmployees,
    setShopShifts,
    setChallenges,
    setRefunds,
    setTransactions,
    findOrCreateCategory,
    updateStreak,
    onUpdateTransaction,
    setDebts,
    setBudgets,
    onSaveProduct,
    onRefreshPrices,
  } = dataContext;

  const handleContributeToGoal = (goalId: string, amount: number, accountId: string) => {
    const goal = appState.goals.find(g => g.id === goalId);
    if (!goal) return;

    const transaction: Transaction = {
        id: self.crypto.randomUUID(),
        accountId,
        description: `Contribution to goal: ${goal.name}`,
        amount,
        type: TransactionType.EXPENSE,
        categoryId: findOrCreateCategory('Savings & Investment / Goal Contributions', TransactionType.EXPENSE),
        date: new Date().toISOString(),
    };
    setTransactions(prev => [transaction, ...prev]);
    updateStreak();

    const newCurrentAmount = goal.currentAmount + amount;
    const updatedGoal = { ...goal, currentAmount: newCurrentAmount };
    setGoals(prev => prev.map(g => g.id === goalId ? updatedGoal : g));

    if (newCurrentAmount >= goal.targetAmount && goal.currentAmount < goal.targetAmount) {
        onGoalComplete();
    }
  };

  const handlePayRecurring = (item: RecurringTransaction) => {
    const transaction: Transaction = {
        id: self.crypto.randomUUID(),
